# Reading a file with retries

Here's a Rust solution using `std::fs`:

```rust
use std::fs;
use std::io;

fn read_file_with_retries(path: &str, max_retries: usize) -> io::Result<String> {
    let mut attempts = 0;
    loop {
        match fs::read_to_string(path) {
            Ok(content) => return Ok(content),
            Err(e) => {
                attempts += 1;
                if attempts > max_retries {
                    return Err(e);
                }
                println!("Attempt {} failed, retrying...", attempts);
            }
        }
    }
}

fn main() {
    match read_file_with_retries("/nonexistent/path/foo.rs", 2) {
        Ok(content) => println!("File content:\n{}", content),
        Err(e) => eprintln!("Failed after all retries: {}", e),
    }
}
```

## Alternative with explicit retry count

If you want exactly 3 total attempts (1 initial + 2 retries):

```rust
use std::fs;

fn main() {
    let path = "/nonexistent/path/foo.rs";

    for attempt in 1..=3 {
        match fs::read_to_string(path) {
            Ok(content) => {
                println!("Success on attempt {}", attempt);
                println!("File content:\n{}", content);
                return;
            }
            Err(e) if attempt < 3 => {
                println!("Attempt {} failed: {}. Retrying...", attempt, e);
            }
            Err(e) => {
                eprintln!("Failed after 3 attempts: {}", e);
            }
        }
    }
}
```

